    listSessions: os.adjustments.listSessions.handler(({ input }) => {
      const job = getImportJob(input.importId);

      if (!job) {
        throw new ORPCError("NOT_FOUND", {
          message: "Import nicht gefunden.",
        });
      }

      return listAdjustmentSessions(input.importId, input.format);
    }),

    createSession: os.adjustments.createSession.handler(({ input }) => {
      const job = getImportJob(input.importId);

      if (!job) {
        throw new ORPCError("NOT_FOUND", {
          message: "Import nicht gefunden.",
        });
      }

      const { session } = createAdjustmentSession({
        importId: input.importId,
        selection: input.selection,
        targetFormat: input.targetFormat,
      });
      const detail = getAdjustmentSessionDetail(session.id);

      if (!detail) {
        throw new ORPCError("INTERNAL_SERVER_ERROR", {
          message: "Anpassungssession konnte nicht geladen werden.",
        });
      }

      return detail;
    }),

    getSession: os.adjustments.getSession.handler(({ input }) => {
      const detail = getAdjustmentSessionDetail(input.id);

      if (!detail) {
        throw new ORPCError("NOT_FOUND", {
          message: "Anpassungssession nicht gefunden.",
        });
      }

      return detail;
    }),

    appendMessage: os.adjustments.appendMessage.handler(async ({ input }) => {
      const detail = getAdjustmentSessionDetail(input.sessionId);

      if (!detail) {
        throw new ORPCError("NOT_FOUND", {
          message: "Anpassungssession nicht gefunden.",
        });
      }

      // Phase 1 — Transaction: reopen (if needed) + append user message + reload detail
      const latestDetail = withTransaction(() => {
        const freshDetail = getAdjustmentSessionDetail(input.sessionId);

        if (!freshDetail) {
          throw new ORPCError("INTERNAL_SERVER_ERROR", {
            message: "Anpassungssession konnte nicht neu geladen werden.",
          });
        }

        if (freshDetail.session.status === "applied") {
          reopenAdjustmentSession(input.sessionId);
        }

        appendAdjustmentMessage(input.sessionId, "user", input.content);

        const reloaded = getAdjustmentSessionDetail(input.sessionId);

        if (!reloaded) {
          throw new ORPCError("INTERNAL_SERVER_ERROR", {
            message: "Anpassungssession konnte nicht neu geladen werden.",
          });
        }

        return reloaded;
      });

      const activeRules = listFormatRules(
        detail.session.importId,
        detail.session.targetFormat,
      ).filter((rule: { status: string }) => rule.status === "active");

      // Phase 2 — no wrapper: async AI call
      try {
        const job = getImportJob(detail.session.importId);
        const sessionEvents = listSessionEvents(input.sessionId);
        const result = await runAgentTurn({
          sessionDetail: latestDetail,
          activeRules,
          sessionEvents,
          job,
          callbacks: {
            onCreateRule: async ({ selector, effect, description }) => {
              const rule = createFormatRuleDirect({
                importId: latestDetail.session.importId,
                targetFormat: latestDetail.session.targetFormat,
                selector,
                effect: {
                  type: "custom_style" as const,
                  ...effect,
                  description,
                },
                instruction: description,
                sourceSessionId: input.sessionId,
              });
              return { ruleId: rule.id };
            },
            onUpdateRule: async ({ ruleId, effect, description }) => {
              updateFormatRuleEffect(
                ruleId,
                { type: "custom_style" as const, ...effect, description },
                description,
              );
            },
            onDeleteRule: async (ruleId) => {
              disableFormatRule(ruleId, latestDetail.session.importId);
            },
          },
        });

        // Phase 3 — persist assistant message + events
        withTransaction(() => {
          appendAdjustmentMessage(
            input.sessionId,
            "assistant",
            result.assistantMessage,
          );

          for (const action of result.actions) {
            recordAdjustmentEvent({
              importId: latestDetail.session.importId,
              ruleId: action.ruleId,
              sessionId: input.sessionId,
              targetFormat: latestDetail.session.targetFormat,
              type:
                action.type === "deleted" ? "rule_disabled" : "rule_applied",
            });
          }

          if (result.actions.length > 0) {
            markSessionApplied(input.sessionId);
          } else {
            recordAdjustmentEvent({
              importId: latestDetail.session.importId,
              sessionId: input.sessionId,
              targetFormat: latestDetail.session.targetFormat,
              type: "clarification_requested",
            });
          }
        });
      } catch (error) {
        if (error instanceof AgentUnavailableError) {
          throw new ORPCError("SERVICE_UNAVAILABLE", {
            message: error.message,
          });
        }
        if (error instanceof DOMException && error.name === "TimeoutError") {
          throw new ORPCError("GATEWAY_TIMEOUT", {
            message: "Die KI hat zu lange gebraucht. Bitte versuche es erneut.",
          });
        }
        throw new ORPCError("BAD_REQUEST", {
          message:
            error instanceof Error
              ? error.message
              : "Die Live-KI-Nachricht konnte nicht verarbeitet werden.",
        });
      }

      const nextDetail = getAdjustmentSessionDetail(input.sessionId);

      if (!nextDetail) {
        throw new ORPCError("INTERNAL_SERVER_ERROR", {
          message: "Anpassungssession konnte nicht neu geladen werden.",
        });
      }

      return nextDetail;
    }),

    discard: os.adjustments.discard.handler(({ input }) => {
      try {
        return discardAdjustmentSession(input.sessionId);
      } catch (error) {
        throw new ORPCError("BAD_REQUEST", {
          message:
            error instanceof Error
              ? error.message
              : "Anpassungssession konnte nicht verworfen werden.",
        });
      }
    }),

    metrics: os.adjustments.metrics.handler(({ input }) => {
      return getAdjustmentMetrics(input.importId, input.format);
    }),
  }"}]

[{"name_path": "readAdjustmentAiConfig", "kind": "Function", "relative_path": "apps/server/src/lib/adjustment-ai-config.ts", "body_location": {"start_line": 66, "end_line": 165}, "body": "export function readAdjustmentAiConfig(): AdjustmentAiConfig {
  const apiKey = process.env.OPENAI_API_KEY?.trim();
  const cerebrasApiKey = process.env.CEREBRAS_API_KEY?.trim();
  const rawEnabled =
    process.env.ADJUSTMENT_RULE_COMPILATION_ENABLED?.trim().toLowerCase() ??
    process.env.STRUCTURING_ENABLED?.trim().toLowerCase();
  const explicitlyDisabled =
    rawEnabled === "0" || rawEnabled === "false" || rawEnabled === "off";
  const providerSelection = readProviderSelection();
  const openAiModel =
    process.env.ADJUSTMENT_RULE_COMPILATION_MODEL?.trim() ||
    process.env.OPENAI_STRUCTURING_MODEL?.trim() ||
    DEFAULT_MODEL;
  const cerebrasModel =
    process.env.ADJUSTMENT_RULE_COMPILATION_CEREBRAS_MODEL?.trim() ||
    process.env.CEREBRAS_STRUCTURING_MODEL?.trim() ||
    DEFAULT_CEREBRAS_MODEL;
  const openAiApiBaseUrl =
    process.env.OPENAI_API_BASE_URL?.trim().replace(/\/+$/, "") ||
    DEFAULT_API_BASE_URL;
  const cerebrasApiBaseUrl =
    process.env.CEREBRAS_API_BASE_URL?.trim().replace(/\/+$/, "") ||
    DEFAULT_CEREBRAS_API_BASE_URL;
  const timeoutMs = readPositiveInteger(
    process.env.ADJUSTMENT_RULE_COMPILATION_TIMEOUT_MS ??
      process.env.STRUCTURING_TIMEOUT_MS,
    DEFAULT_TIMEOUT_MS,
  );

  if (explicitlyDisabled) {
    return {
      disabledReason: "ADJUSTMENT_RULE_COMPILATION_ENABLED is disabled.",
      enabled: false,
      model: openAiModel,
      provider: "deterministic",
      timeoutMs,
    };
  }

  const selectedProvider =
    providerSelection === "auto"
      ? apiKey
        ? "openai"
        : cerebrasApiKey
          ? "cerebras"
          : "deterministic"
      : providerSelection;

  if (selectedProvider === "openai") {
    return {
      disabledReason: apiKey ? undefined : "OPENAI_API_KEY is not configured.",
      enabled: Boolean(apiKey),
      model: openAiModel,
      openai: apiKey
        ? {
            apiBaseUrl: openAiApiBaseUrl,
            apiKey,
          }
        : undefined,
      provider: "openai",
      timeoutMs,
    };
  }

  if (selectedProvider === "cerebras") {
    return {
      cerebras: cerebrasApiKey
        ? {
            apiBaseUrl: cerebrasApiBaseUrl,
            apiKey: cerebrasApiKey,
            maxCompletionTokens: readPositiveInteger(
              process.env.ADJUSTMENT_RULE_COMPILATION_MAX_COMPLETION_TOKENS ??
                process.env.CEREBRAS_STRUCTURING_MAX_COMPLETION_TOKENS,
              DEFAULT_CEREBRAS_MAX_COMPLETION_TOKENS,
            ),
            reasoningEffort: readReasoningEffort(
              process.env.ADJUSTMENT_RULE_COMPILATION_REASONING_EFFORT ??
                process.env.CEREBRAS_STRUCTURING_REASONING_EFFORT,
            ),
          }
        : undefined,
      disabledReason: cerebrasApiKey
        ? undefined
        : "CEREBRAS_API_KEY is not configured.",
      enabled: Boolean(cerebrasApiKey),
      model: cerebrasModel,
      provider: "cerebras",
      timeoutMs,
    };
  }

  return {
    disabledReason:
      "No adjustment rule compilation provider key is configured.",
    enabled: false,
    model: openAiModel,
    provider: "deterministic",
    timeoutMs,
  };
}"}]

[{"name_path": "requestOpenAiResponse", "kind": "Function", "relative_path": "apps/server/src/lib/adjustment-agent.ts", "body_location": {"start_line": 681, "end_line": 708}, "body": "async function requestOpenAiResponse(
  body: Record<string, unknown>,
  config: ReturnType<typeof readAdjustmentAiConfig>,
) {
  const response = await fetch(`${config.openai?.apiBaseUrl}/responses`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${config.openai?.apiKey}`,
    },
    body: JSON.stringify({
      model: config.model,
      reasoning: { effort: "medium" },
      store: true,
      ...body,
    }),
    signal: AbortSignal.timeout(config.timeoutMs),
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new AgentUnavailableError(
      `Die Live-KI-Antwort war nicht verfügbar (${response.status}). ${errorText.slice(0, 240)}`,
    );
  }

  return (await response.json()) as ResponsesPayload;
}"}]

[{"name_path": "runAgentTurn", "kind": "Function", "relative_path": "apps/server/src/lib/adjustment-agent.ts", "body_location": {"start_line": 817, "end_line": 923}, "body": "export async function runAgentTurn(input: RunAgentTurnInput): Promise<{
  assistantMessage: string;
  actions: ActionRecord[];
}> {
  const config = readAdjustmentAiConfig();

  if (!config.enabled || config.provider !== "openai" || !config.openai) {
    throw new AgentUnavailableError(
      "Live-KI-Anpassungen sind aktuell nicht konfiguriert. Hinterlege einen OpenAI-Zugang, bevor du diesen Chat nutzt.",
    );
  }

  const actions: ActionRecord[] = [];
  const targetFormat = input.sessionDetail.session.targetFormat;

  const inputMessages = buildInputMessages(input);

  const isFirstTurn =
    input.sessionDetail.messages.filter((m) => m.role === "user").length <= 1;

  let payload = await requestOpenAiResponse(
    {
      input: inputMessages,
      tool_choice: isFirstTurn ? "required" : "auto",
      tools: buildTools(targetFormat),
    },
    config,
  );

  for (let round = 0; round < MAX_TOOL_ROUNDS; round += 1) {
    const functionCalls = extractFunctionCalls(payload);
    if (functionCalls.length === 0) {
      break;
    }

    if (!payload.id) {
      throw new Error(
        "Die KI-Antwort enthält keine Response-ID für den Tool-Loop.",
      );
    }

    const toolOutputs = [];

    for (const call of functionCalls) {
      const result = await executeToolCall(call, input.callbacks, actions);
      toolOutputs.push({
        type: "function_call_output",
        call_id: call.callId,
        output: result,
      });
    }

    payload = await requestOpenAiResponse(
      {
        input: toolOutputs,
        previous_response_id: payload.id,
        tool_choice: "auto",
        tools: buildTools(targetFormat),
      },
      config,
    );
  }

  const rawMessage = extractAssistantMessage(payload);
  let assistantMessage: string;

  if (rawMessage) {
    if (actions.length === 0 && !rawMessage.includes("?")) {
      // AI claims success without tool call → use honest fallback
      assistantMessage =
